var marker,position_data,map,script=document.createElement("script");function initMap(){let e=document.getElementById("latbox").value,t=document.getElementById("lngbox").value;var a=new google.maps.LatLng(18.7939983,98.9214578);""!=e&""!=t&&(a=new google.maps.LatLng(e,t)),map=new google.maps.Map(document.getElementById("map-panel"),{center:a,zoom:11,mapTypeId:google.maps.MapTypeId.ROADMAP}),marker=new google.maps.Marker({position:a,map:map,title:"Set lat/lon values for this property",draggable:!0}),document.getElementById("latbox").value=marker.getPosition().lat(),document.getElementById("lngbox").value=marker.getPosition().lng(),map.addListener("click",function(e){marker.setMap(null),latEvent=e.latLng.lat(),lngEvent=e.latLng.lng(),map.panTo(e.latLng),$("#map-panel").attr("data-lat",latEvent),$("#map-panel").attr("data-lng",lngEvent),position_data=new google.maps.LatLng(latEvent,lngEvent),marker=new google.maps.Marker({position:position_data,map:map,draggable:!0}),document.getElementById("latbox").value=latEvent,document.getElementById("lngbox").value=lngEvent}),google.maps.event.addListener(marker,"dragend",function(e){document.getElementById("latbox").value=this.getPosition().lat(),document.getElementById("lngbox").value=this.getPosition().lng()})}function changeLatLng(){let e=document.getElementById("latbox").value,t=document.getElementById("lngbox").value;marker.setMap(null),position_data=new google.maps.LatLng(e,t),marker=new google.maps.Marker({position:position_data,map:map,draggable:!0}),map.panTo(position_data)}script.type="text/javascript",script.src="https://maps.googleapis.com/maps/api/js?key=AIzaSyA_is9SOxGUJQOTrgdmcCZf_ZiI1oIFSd0&callback=initMap",document.body.appendChild(script);